// Hardware-ready mounting plate — a single flat plate that showcases four
// printFit builders at once: M3 counterbored screw holes in the corners,
// M4 captive nut pockets along the centre spine, and an alignment pin + socket
// pair on the short edges so two plates stack and register perfectly.
const { Manifold, printFit } = api;

const W = 80, D = 50, T = 6;   // plate dimensions
const cornerInset = 8;          // screw holes inset from corners
const nutSpacing = 22;          // nut pocket spacing from centre

// ---- Base plate ----
let plate = Manifold.cube([W, D, T], false);

// ---- M3 socket-head counterbored holes in the four corners ----
for (const [x, y] of [
  [cornerInset,     cornerInset],
  [W - cornerInset, cornerInset],
  [cornerInset,     D - cornerInset],
  [W - cornerInset, D - cornerInset],
]) {
  plate = plate.subtract(
    printFit.screwHole({ size: 'M3', length: T, head: 'socket' })
      .translate([x, y, T]),
  );
}

// ---- M4 captive nut pockets along the midline (for T-slot or panel nuts) ----
for (const x of [W / 2 - nutSpacing, W / 2 + nutSpacing]) {
  // nutPocket opens at z=0; subtract from the bottom face (z=0, pointing -Z).
  plate = plate.subtract(
    printFit.nutPocket({ size: 'M4', depth: 4, captive: true })
      .translate([x, D / 2, 0]),
  );
}

// ---- Alignment pin on the +X edge, socket on the -X edge ----
// Pin rises 5 mm above the plate; embedded 0.5 mm into the face for a solid union.
plate = plate.add(
  printFit.pin({ diameter: 4, length: 6 })
    .translate([W - 0.5, D / 2, T / 2]),
);
// Socket is a negative cut into the -X face.
plate = plate.subtract(
  printFit.socket({ diameter: 4, depth: 5, fit: 'snug' })
    .rotate([0, -90, 0])
    .translate([0, D / 2, T / 2]),
);

return plate;
